CREATE TABLE IF NOT EXISTS revenue_dashboard_snapshot(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,project_id BIGINT NOT NULL,snapshot_date DATE NOT NULL,formula_version VARCHAR(64) NOT NULL,confirmed_revenue DECIMAL(18,2) NOT NULL,settled_amount DECIMAL(18,2) NOT NULL,receivable_amount DECIMAL(18,2) NOT NULL,outstanding_amount DECIMAL(18,2) NOT NULL,overdue_amount DECIMAL(18,2) NOT NULL,collected_amount DECIMAL(18,2) NOT NULL,invoiced_amount DECIMAL(18,2) NOT NULL,collection_rate DECIMAL(12,6) NOT NULL,refreshed_at TIMESTAMP NOT NULL,refresh_mode VARCHAR(32) NOT NULL,CONSTRAINT fk_revenue_snapshot_project FOREIGN KEY(project_id) REFERENCES pm_project(id));
CREATE UNIQUE INDEX IF NOT EXISTS uk_revenue_snapshot ON revenue_dashboard_snapshot(tenant_id,project_id,snapshot_date);
CREATE TABLE IF NOT EXISTS sales_invoice_review(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,invoice_id BIGINT NOT NULL,raw_result_json CLOB NOT NULL,confidence DECIMAL(5,4) NOT NULL,comparison_json CLOB,review_status VARCHAR(32) DEFAULT 'PENDING' NOT NULL,reviewer_id BIGINT,reviewed_at TIMESTAMP,review_note VARCHAR(500),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,CONSTRAINT fk_sales_invoice_review_invoice FOREIGN KEY(invoice_id) REFERENCES sales_invoice(id));
CREATE TABLE IF NOT EXISTS revenue_import_batch(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,import_type VARCHAR(32) NOT NULL,project_id BIGINT NOT NULL,file_name VARCHAR(255) NOT NULL,file_hash VARCHAR(64) NOT NULL,status VARCHAR(32) NOT NULL,total_rows INT NOT NULL,valid_rows INT NOT NULL,invalid_rows INT NOT NULL,diff_summary_json CLOB,created_by BIGINT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,applied_at TIMESTAMP,CONSTRAINT fk_revenue_import_project FOREIGN KEY(project_id) REFERENCES pm_project(id));
CREATE UNIQUE INDEX IF NOT EXISTS uk_revenue_import_hash ON revenue_import_batch(tenant_id,import_type,project_id,file_hash);
CREATE TABLE IF NOT EXISTS revenue_import_row(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,batch_id BIGINT NOT NULL,row_no INT NOT NULL,input_json CLOB NOT NULL,diff_json CLOB,validation_status VARCHAR(32) NOT NULL,validation_message VARCHAR(1000),CONSTRAINT fk_revenue_import_row_batch FOREIGN KEY(batch_id) REFERENCES revenue_import_batch(id));
CREATE UNIQUE INDEX IF NOT EXISTS uk_revenue_import_row ON revenue_import_row(batch_id,row_no);
CREATE TABLE IF NOT EXISTS revenue_audit_event(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,event_type VARCHAR(64) NOT NULL,business_type VARCHAR(64) NOT NULL,business_id BIGINT NOT NULL,project_id BIGINT,operator_id BIGINT,event_at TIMESTAMP NOT NULL,archive_bucket VARCHAR(32) DEFAULT 'HOT' NOT NULL,payload_json CLOB NOT NULL,payload_hash VARCHAR(64) NOT NULL);
